{"procName":"dbo.tr_sanpham_nhamay_create","body":"CREATE PROCEDURE [dbo].[TR_SANPHAM_NHAMAY_CREATE]
(
  @masp_nhamay nvarchar(50), 
  @tensp nvarchar(MAX), 
  @nguoitao nvarchar(50), 
  @ngaytao datetime, 
  @nguoisua nvarchar(50),
  @ngaysua datetime, 
  @active bit,
  @hehang nvarchar(50) = NULL,
  @IsGoVan bit = NULL,
  @IsNguKim bit = NULL,
  @IsBaoBi bit = NULL,
  @IsSon bit = NULL,
  @IsVeneer bit = NULL,
  @IsBVKT bit = NULL,
  @IsBVDG bit = NULL,
  @IsBVAI bit = NULL,
  @phienban int = NULL,
  @masp_goc nvarchar(50) = NULL 
)
AS
IF EXISTS (SELECT * FROM tr_sanpham_nhamay WHERE masp_nhamay = @masp_nhamay)
BEGIN
  UPDATE tr_sanpham_nhamay
  SET tensp = @tensp, 
      nguoisua = @nguoisua, 
      ngaysua = @ngaysua, 
      active = @active,
      hehang = @hehang,
      IsGoVan = @IsGoVan,
      IsNguKim = @IsNguKim,
      IsBaoBi = @IsBaoBi,
      IsSon = @IsSon,
      IsVeneer = @IsVeneer,
      IsBVKT = @IsBVKT,
      IsBVDG = @IsBVDG,
      IsBVAI = @IsBVAI,
	  phienban = @phienban,
	  masp_goc = @masp_goc
  WHERE masp_nhamay = @masp_nhamay

  UPDATE tr_sanpham
  SET tensp = @tensp, hehang = @hehang
  WHERE masp_nhamay = @masp_nhamay
END
ELSE
BEGIN
  INSERT INTO tr_sanpham_nhamay
  (
    masp_nhamay, 
    tensp, 
    nguoitao, 
    ngaytao, 
    nguoisua,
    ngaysua, 
    active,
    hehang,
    IsGoVan,
    IsNguKim,
    IsBaoBi,
    IsSon,
    IsVeneer,
    IsBVKT,
    IsBVDG,
    IsBVAI,
	phienban,
	masp_goc
  )
  VALUES
  (
    @masp_nhamay, 
    @tensp, 
    @nguoitao, 
    @ngaytao, 
    @nguoisua,
    @ngaysua, 
    @active,
    @hehang,
    @IsGoVan,
    @IsNguKim,
    @IsBaoBi,
    @IsSon,
    @IsVeneer,
    @IsBVKT,
    @IsBVDG,
    @IsBVAI,
	@phienban,
	@masp_goc
  )
END","parseAnalysis":{"readsTables":["dbo.tr_sanpham_nhamay"],"writesTables":["dbo.tr_sanpham","dbo.tr_sanpham_nhamay"],"flags":["writes-multi-table"],"suggestedTier":"D"},"tablesEnriched":{"dbo.dqt_pallet_chitiet":"dqt_pallet_chitiet","dbo.dqt_thongke_phoi":"dqt_thongke_phoi","dbo.mes_hoso_donhang":"mes_hoso_donhang","dbo.ps_kehoach_donhang":"ps_kehoach_donhang","dbo.ps_kehoach_donhang_trangthai":"ps_kehoach_donhang_trangthai","dbo.tr_bophan":"tr_bophan","dbo.tr_chitiet_hangtrang":"tr_chitiet_hangtrang","dbo.tr_common":"tr_common","dbo.tr_dinhmuc_donggoi":"tr_dinhmuc_donggoi","dbo.tr_dinhmuc_govan":"tr_dinhmuc_govan","dbo.tr_dinhmuc_hangtrang":"tr_dinhmuc_hangtrang","dbo.tr_dinhmuc_ngukim":"tr_dinhmuc_ngukim","dbo.tr_dinhmuc_son":"tr_dinhmuc_son","dbo.tr_dinhmuc_son_new":"tr_dinhmuc_son_new","dbo.tr_dinhmuc_son_theomau":"tr_dinhmuc_son_theomau","dbo.tr_dondathang":"tr_dondathang","dbo.tr_dondathang_chitiet":"tr_dondathang_chitiet","dbo.tr_gridview_column":"tr_gridview_column","dbo.tr_luutrinh_sanxuat":"tr_luutrinh_sanxuat","dbo.tr_material":"tr_material","dbo.tr_nguyenlieu_gva":"tr_nguyenlieu_gva","dbo.tr_order":"tr_order","dbo.tr_order_detail":"tr_order_detail","dbo.tr_sanpham":"tr_sanpham","dbo.tr_tinhtrang_fsc":"tr_tinhtrang_fsc"}}
